import React, { useState, useEffect, useMemo, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import dayjs from "dayjs";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function SupportManagement() {
  const [supports, setSupports] = useState([]);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const [filters, setFilters] = useState({
    search: "",
    status: "",
  });

  const [currentPage, setCurrentPage] = useState(1);
  const groupsPerPage = 5;

  const [formData, setFormData] = useState({
    id: null,
    description: "",
    status: "",
  });

  const editModalRef = useRef(null);

  /* ================= FETCH ================= */
  function fetchSupports() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/supports", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((res) => {
        if (res.data.success) {
          setSupports(res.data.data);
        } else {
          toast.error("Failed to fetch supports");
        }
      })
      .catch(() => toast.error("Error fetching supports"))
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) navigate("/");
    else fetchSupports();
  }, [navigate]);

  /* ================= GROUPING ================= */
  const groupedSupports = useMemo(() => {
    const mains = supports.filter((s) => s.reqType === "Main");

    return mains.map((main) => {
      const followups = supports
        .filter(
          (f) =>
            f.reqType === "Followup" &&
            f.reqId === main.id
        )
        .sort(
          (a, b) =>
            new Date(a.createdAt) -
            new Date(b.createdAt)
        );

      return { main, followups };
    });
  }, [supports]);

  /* ================= FILTER ================= */
  const filteredGroups = groupedSupports.filter(
    (group) => {
      const combinedText =
        (group.main.description || "") +
        (group.main.userFullName || "") +
        (group.main.employeeName || "");

      const searchMatch = filters.search
        ? combinedText
            .toLowerCase()
            .includes(filters.search.toLowerCase())
        : true;

      const statusMatch = filters.status
        ? group.main.status === filters.status
        : true;

      return searchMatch && statusMatch;
    }
  );

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * groupsPerPage;
  const indexOfFirst = indexOfLast - groupsPerPage;

  const currentGroups = filteredGroups.slice(
    indexOfFirst,
    indexOfLast
  );

  const totalPages =
    Math.ceil(filteredGroups.length / groupsPerPage) || 1;

  /* ================= EDIT ================= */
  function handleEdit(support) {
    if (support.reqType !== "Followup") {
      toast.error("Main request cannot be edited");
      return;
    }

    setFormData({
      id: support.id,
      description: support.description,
      status: support.status,
    });

    const modal = new Modal(
      document.getElementById("editSupportModal")
    );
    editModalRef.current = modal;
    modal.show();
  }

  function handleSubmit(e) {
    e.preventDefault();
    const token = Cookies.get("adminToken");

    axios
      .put(
        API_BASE_URL + "/supports/" + formData.id,
        formData,
        {
          headers: {
            Authorization: "Bearer " + token,
          },
        }
      )
      .then(() => {
        toast.success("Followup updated");
        fetchSupports();
        editModalRef.current.hide();
      })
      .catch(() => toast.error("Update failed"));
  }

  /* ================= DELETE ================= */
  function handleDelete(support) {
    if (support.reqType !== "Followup") {
      toast.error("Main request cannot be deleted");
      return;
    }

    if (!window.confirm("Delete this followup?"))
      return;

    const token = Cookies.get("adminToken");

    axios
      .delete(
        API_BASE_URL + "/supports/" + support.id,
        {
          headers: {
            Authorization: "Bearer " + token,
          },
        }
      )
      .then(() => {
        toast.success("Deleted");
        fetchSupports();
      })
      .catch(() => toast.error("Delete failed"));
  }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />

            {/* Back */}
      <div className="row mb-3">
        <div className="col">
          <i
            className="fa fa-arrow-left mt-2"
            style={{ cursor: "pointer" }}
            onClick={() => navigate("/dashboard")}
          ></i>
        </div>
      </div>

      {/* Header */}
      <div className="row g-3 mb-3">
        <div className="col-md-12 col-12">
          <h4 className="fw-bold mb-0"> Support Management</h4>
        </div>
      </div>

      {/* Filters */}
      <div className="row g-3 mb-3">
        <div className="col-md-6">
          <input
            type="text"
            className="form-control form-control-sm"
            placeholder="Search..."
            value={filters.search}
            onChange={(e) =>
              setFilters({
                ...filters,
                search: e.target.value,
              })
            }
          />
        </div>

        <div className="col-md-6">
          <select
            className="form-select form-select-sm"
            value={filters.status}
            onChange={(e) =>
              setFilters({
                ...filters,
                status: e.target.value,
              })
            }
          >
            <option value="">Status</option>
            <option value="Open">Open</option>
            <option value="In Progress">
              In Progress
            </option>
            <option value="Closed">Closed</option>
          </select>
        </div>
      </div>

      {/* TABLE */}
      <div className="card border-0 mb-3">
        {loading ? (
          <div className="text-center p-3">
            Loading...
          </div>
        ) : (
          <div className="table-responsive rounded">
            <table className="table table-striped small mb-0">
              <thead className="table-dark">
                <tr>
                  <th>ID</th>
                  <th>User</th>
                  <th>Status</th>
                  <th>Conversation</th>
                  <th>Last Updated</th>
                </tr>
              </thead>

              <tbody>
                {currentGroups.map((group) => (
                  <tr key={group.main.id}>
                    <td>{group.main.id}</td>

                    <td>
                      {group.main.userFullName}
                    </td>

                    <td>{group.main.status}</td>

                    {/* Conversation */}
                    <td
                      style={{ minWidth: "400px" }}
                    >
                      {/* Main */}
                      <div className="p-2 mb-2 bg-light border rounded">
                        <strong>Main:</strong>
                        <div>
                          {
                            group.main
                              .description
                          }
                        </div>
                        <small className="text-muted">
                          {dayjs(
                            group.main.createdAt
                          ).format(
                            "DD MMM YYYY hh:mm A"
                          )}
                        </small>
                      </div>

                      {/* Followups */}
                      {group.followups.map(
                        (f) => (
                          <div
                            key={f.id}
                            className="p-2 mb-2 border rounded"
                          >
                            <strong>
                              Followup:
                            </strong>
                            <div>
                              {
                                f.description
                              }
                            </div>

                            <small className="text-muted">
                              {dayjs(
                                f.createdAt
                              ).format(
                                "DD MMM YYYY hh:mm A"
                              )}
                            </small>

                            <div className="mt-1">
                              <i
                                className="fa-solid fa-pen text-primary me-2"
                                style={{
                                  cursor:
                                    "pointer",
                                }}
                                onClick={() =>
                                  handleEdit(
                                    f
                                  )
                                }
                              ></i>

                              <i
                                className="fa-solid fa-trash text-danger"
                                style={{
                                  cursor:
                                    "pointer",
                                }}
                                onClick={() =>
                                  handleDelete(
                                    f
                                  )
                                }
                              ></i>
                            </div>
                          </div>
                        )
                      )}
                    </td>

                    <td>
                      {dayjs(
                        group.main.updatedAt
                      ).format(
                        "DD MMM YYYY hh:mm A"
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Pagination */}
      <div className="d-flex justify-content-between mb-3">
        <div>
          Page {currentPage} of {totalPages} • {filteredGroups.length}
        </div>
        <div>
          <button
            className="btn btn-sm border-0"
            disabled={currentPage === 1}
            onClick={() =>
              setCurrentPage((p) => p - 1)
            }
          >
           <i className="fa-solid fa-chevron-left"></i>
          </button>
          <button
            className="btn btn-sm border-0"
            disabled={
              currentPage === totalPages
            }
            onClick={() =>
              setCurrentPage((p) => p + 1)
            }
          >
           <i className="fa-solid fa-chevron-right"></i>
          </button>
        </div>
      </div>

      {/* Edit Modal */}
      <div
        className="modal fade"
        id="editSupportModal"
      >
        <div className="modal-dialog">
          <div className="modal-content">
            <form onSubmit={handleSubmit}>
              <div className="modal-header">
                <h5>Edit Followup</h5>
                <button
                  className="btn-close"
                  data-bs-dismiss="modal"
                ></button>
              </div>

              <div className="modal-body">
                <select
                  className="form-select mb-3"
                  value={formData.status}
                  onChange={(e) =>
                    setFormData({
                      ...formData,
                      status:
                        e.target.value,
                    })
                  }
                >
                  <option value="In Progress">
                    In Progress
                  </option>
                  <option value="Closed">
                    Closed
                  </option>
                </select>

                <textarea
                  className="form-control"
                  value={
                    formData.description
                  }
                  onChange={(e) =>
                    setFormData({
                      ...formData,
                      description:
                        e.target.value,
                    })
                  }
                  required
                />
              </div>

              <div className="modal-footer">
                <button className="btn btn-primary">
                  Update
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

export default SupportManagement;
